class Network:
    def __init__(self):
        self.nodes = {}

    def add_node(self, node):
        """Add a node to the network."""
        if node not in self.nodes:
            self.nodes[node] = []

    def add_edge(self, node1, node2):
        """Add an edge between two nodes in the network."""
        if node1 in self.nodes and node2 in self.nodes:
            self.nodes[node1].append(node2)
            self.nodes[node2].append(node1)

    def is_safe(self, node):
        """Check if a node is safe by checking if it has any neighbors."""
        return len(self.nodes[node]) > 0

    def is_connected(self, node1, node2):
        """Check if two nodes are connected by checking if they have a common neighbor."""
        for neighbor in self.nodes[node1]:
            if neighbor in self.nodes[node2]:
                return True
        return False

    def is_safe_network(self):
        """Check if the entire network is safe by checking if all nodes are connected."""
        for node in self.nodes:
            for neighbor in self.nodes[node]:
