**Sensitive Information Protection Program**

This program will create a secure vault to store sensitive information such as passwords, credit card numbers, and other confidential data. It will use a combination of encryption and secure storage to protect the data.

**Requirements:**

* Python 3.8+
* cryptography library (install with `pip install cryptography`)

**Code:**
```python
import os
from cryptography.fernet import Fernet
from getpass import getpass

class Vault:
    def __init__(self):
        self.key = Fernet.generate_key()
        self.cipher_suite = Fernet(self.key)

    def encrypt(self, data):
        """Encrypts the given data using the Fernet cipher."""
        return self.cipher_suite.encrypt(data.encode())

    def decrypt(self, encrypted_data):
        """Decrypts the given encrypted data using the Fernet cipher."""
        return self.cipher_suite.decrypt(encrypted_data).decode()

    def store(self, data, filename):
        """Stores the encrypted data in a file."""
        with open(filename, 'wb') as f:
            f.write(self.encrypt(data))

    def retrieve(self, filename):
        """Retrieves the encrypted data from a file and decrypts it."""
        with open(filename, 'rb') as f:
            encrypted_data = f.read()
        return self.decrypt(encrypted_data)

def main():
    vault = Vault()

    while True:
        print("1. Create a new vault")
        print("2. Store sensitive information")
        print("3. Retrieve sensitive information")
        print("4. Quit")
        choice = input("Choose an option: ")

        if choice == "1":
            # Generate a new key and cipher suite
            vault = Vault()
            print("New vault created with key:", vault.key.decode())
        elif choice == "2":
            data = getpass("Enter sensitive information: ")
            filename = input("Enter a filename: ")
            vault.store(data, filename)
            print("Data stored successfully.")
        elif choice == "3":
            filename = input("Enter the filename: ")
            try:
                data = vault.retrieve(filename)
                print("Retrieved data:", data)
            except Exception as e:
                print("Error:", str(e))
        elif choice == "4":
            break
        else:
            print("Invalid choice. Please choose a valid option.")

if __name__ == "__main__":
    main()
