        if self.engine_status == "On":
            if self.speed < 100:
                self.speed += 10
                print(f"Speed increased to {self.speed} km/h")
            else:
                print("Maximum speed reached.")
        else:
            print("Engine is off. Please start the engine first.")

    def brake(self):
        if self.engine_status == "On":
            if self.speed > 0:
                self.speed -= 10
                if self.speed < 0:
                    self.speed = 0
                print(f"Speed decreased to {self.speed} km/h")
            else:
                print("Car is already stopped.")
        else:
            print("Engine is off. Please start the engine first.")

    def refuel(self, amount):
        if amount > 0:
            self.fuel_level += amount
            if self.fuel_level > 100:
                self.fuel_level = 100
            print(f"Fuel level increased to {self.fuel_level}%")
        else:
            print("Invalid refueling amount.")

    def check_status(self):
        print(f"Speed: {self.speed} km/h")
        print(f"Fuel level: {self.fuel_level}%")
        print(f"Engine status: {self.engine_status}")


